      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projects = require('../projects/service').getAllProjects();
const tasks = {};

function createTask(projectId, { title }) {
  if (!title) throw { code: 'invalid_input', message: 'Title is required' };
  const project = projects.find(p => p.id === projectId);
  if (!project) throw { code: 'not_found', message: 'Project not found' };
  const id = randomUUID();
  if (!tasks[projectId]) tasks[projectId] = [];
  tasks[projectId].push({ id, title, status: 'open' });
  return tasks[projectId][tasks[projectId].length - 1];
}

function getAllTasks(projectId, status) {
  const project = projects.find(p => p.id === projectId);
  if (!project) throw { code: 'not_found', message: 'Project not found' };
  return tasks[projectId] ? (status ? tasks[projectId].filter(t => t.status === status) : tasks[projectId]) : [];
}

function updateTask(projectId, taskId, { status }) {
  const project = projects.find(p => p.id === projectId);
  if (!project) throw { code: 'not_found', message: 'Project not found' };
  const taskIndex = tasks[projectId] ? tasks[projectId].findIndex(t => t.id === taskId) : -1;
  if (taskIndex === -1) throw { code: 'not_found', message: 'Task not found' };
  if (!['open', 'done'].includes(status)) throw { code: 'invalid_input', message: 'Invalid status' };
  tasks[projectId][taskIndex].status = status;
  return tasks[projectId][taskIndex];
}

module.exports = { createTask, getAllTasks, updateTask };
