      "path": "src/modules/comments/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projects = require('../projects/service').getAllProjects();
const tasks = require('../tasks/service').getAllTasks;
const comments = {};

function addComment(projectId, taskId, { message }) {
  if (!message) throw { code: 'invalid_input', message: 'Message is required' };
  const project = projects.find(p => p.id === projectId);
  if (!project) throw { code: 'not_found', message: 'Project not found' };
  const task = tasks(projectId).find(t => t.id === taskId);
  if (!task) throw { code: 'not_found', message: 'Task not found' };
  const id = randomUUID();
  if (!comments[taskId]) comments[taskId] = [];
  comments[taskId].push({ id, message });
  return comments[taskId][comments[taskId].length - 1];
}

function getAllComments(projectId, taskId) {
  const project = projects.find(p => p.id === projectId);
  if (!project) throw { code: 'not_found', message: 'Project not found' };
  const task = tasks(projectId).find(t => t.id === taskId);
  if (!task) throw { code: 'not_found', message: 'Task not found' };
  return comments[taskId] || [];
}

module.exports = { addComment, getAllComments };
